INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3f10900-0000-4000-8000-000000000000','a3f00000-0000-4000-8000-000000000000','確認テスト ─ 経営者の法的責任','quiz',NULL,NULL,NULL,3,2),
  ('a3f20900-0000-4000-8000-000000000000','a3f00000-0000-4000-8000-000000000000','確認テスト ─ 内部統制とコンプライアンス体制','quiz',NULL,NULL,NULL,3,4),
  ('a3f30900-0000-4000-8000-000000000000','a3f00000-0000-4000-8000-000000000000','確認テスト ─ ステークホルダーマネジメント','quiz',NULL,NULL,NULL,3,6)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3f10900-0000-4000-8000-000000000000','善管注意義務と忠実義務を一行でまとめると、それぞれ何を求める約束か。','善管注意義務は「ちゃんと考えて判断せよ」、忠実義務は「会社のために判断せよ」','善管注意義務は「会社のために判断せよ」、忠実義務は「ちゃんと考えて判断せよ」','善管注意義務は「結果を出せ」、忠実義務は「スピードを上げよ」','善管注意義務は「利益相反を開示せよ」、忠実義務は「記録を残せ」','A',0),
('a3f10900-0000-4000-8000-000000000000','本文が示す「経営判断の原則」の考え方はどれか。','結果が悪ければ即、義務違反として責任を問う','適切な過程を踏んで下した判断は、結果が悪くても簡単には責任を問われない','会議体を通しさえすれば、過程は問われない','利益相反さえなければ、情報収集は不要である','B',1),
('a3f10900-0000-4000-8000-000000000000','設備投資が苦戦したのに判断の過程は誠実だったとされた理由として、本文に合うものはどれか。','結果的に投資が黒字化したから','トップが一人で素早く決断したから','需要の見通しや回収の見込みを数字で出し、外部の専門家にも見てもらってから決めたから','利害関係者全員の同意を得たから','C',2),
('a3f20900-0000-4000-8000-000000000000','本文が示す内部統制の本質を一行で言うと、どれか。','社員を監視し、疑うための管理の仕組みである','優秀な一人に権限を集め、効率を上げる仕組みである','良心を鍛え、悪い人を見つけてなくす仕組みである','人が間違えずに済むように、すきまをふさぐ堤防である','D',0),
('a3f20900-0000-4000-8000-000000000000','本文で、人が性格に関係なく間違える条件として挙げられている三つはどれか。','動機・機会・正当化','空気・すきま・声','情報・利害・記録','見る・聴く・つなぐ','A',1),
('a3f20900-0000-4000-8000-000000000000','「工事②:権限を、分ける」で最も効く予防とされているのはどれか。','チェックのルールをできるだけ多く増やすこと','一人で完結できないようにすること','信頼できる一人に出金も記帳も口座管理も任せること','立派な倫理ポスターを掲示すること','B',2),
('a3f30900-0000-4000-8000-000000000000','本文が示すステークホルダーマネジメントの本質はどれか。','声の大きい相手に合わせ、優先順位を決めること','対立する利害の真ん中で「結び目」になること','すべての利害関係者を同じだけ満たすこと','最も利益をもたらす相手を一つ選ぶこと','B',0),
('a3f30900-0000-4000-8000-000000000000','型②で聴き取るべき「奥の関心(インタレスト)」と対比されるのは何か。','表に出た要求(ポジション)','重なり(共通の利益)','声の大きさ','渡せる資源の量','A',1),
('a3f30900-0000-4000-8000-000000000000','型④で、応えられない要求に対して本文が最も避けるべきとする対応はどれか。','いまはここまでしかできないと正直に伝える','応えられる範囲と、その道筋を示す','沈黙して期待させ、結果的に裏切る','重要な相手への説明は専門家に確認する','C',2);
